{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleMultilineStringClosingQuotesConsistencyTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

internal class IndentationRuleMultilineStringClosingQuotesConsistencyTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a raw string literal as function body expression then allow the closing quotes aligned with function indentation`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                some text
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()

        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a raw string literal returned from a function block then allow the closing quotes aligned with return indentation`() {
        val code =
            """
            fun foo2(): String {
                return $MULTILINE_STRING_QUOTE
                    some text
                $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()

        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

